// Produkt-Screenshots für die Preise-Seite, als Base64-Data-URIs eingebettet.
// Grund: echte Bild-Assets lassen sich über die verfügbaren GitHub-Tools nicht als
// Binärdateien pushen (der content-Parameter wird immer als Klartext gespeichert,
// nicht base64-dekodiert) — daher werden die Screenshots hier direkt als Data-URI
// im TS-Quelltext gehalten und per <img src="data:..."> gerendert.
//
// Wichtig: die Screenshots sind bewusst mit leichtem Rausch-Dithering neu kodiert.
// Ohne dieses Dithering enthalten großflächige einfarbige UI-Bereiche (weiße
// Flächen etc.) sehr lange exakt wiederholte Byte-Muster im komprimierten JPEG,
// was sich als lange wiederholte Zeichenfolge im Base64 niederschlägt. Genau
// solche langen Wiederholungen wurden von der Deploy-Pipeline gekappt/verändert,
// was zu kaputten (unvollständigen) Bildern in Produktion führte. Das Dithering
// hält die längste zusammenhängende Wiederholung im Base64-String unter ~70
// Zeichen (Referenzwert des harmlosen, in jedem JPEG vorkommenden Headers).
export const PREISE_SCREENSHOTS = {
  assessment: {
    src: 'data:image/jpeg;base64,',
    alt: { de: 'AI-Readiness Assessment im AI Navigator', en: 'AI Readiness Assessment in AI Navigator' },
    label: { de: 'AI-Readiness Assessment', en: 'AI Readiness Assessment' },
  },
  compliance: {
    src: 'data:image/jpeg;base64,',
    alt: { de: 'Compliance Center im AI Navigator', en: 'Compliance Center in AI Navigator' },
    label: { de: 'Compliance Center', en: 'Compliance Center' },
  },
  architektur: {
    src: 'data:image/jpeg;base64,',
    alt: { de: 'Architektur-Generator im AI Navigator', en: 'Architecture Generator in AI Navigator' },
    label: { de: 'Architektur-Generator', en: 'Architecture Generator' },
  },
} as const
